#!/usr/bin/env node

const { execSync } = require('child_process');
const { cpus } = require('os');
const fs = require('fs');
const path = require('path');

const PARALLEL_JOBS = cpus().length;
const START_TIME = Date.now();

function log(message, level = 'INFO') {
  const timestamp = new Date().toISOString();
  const elapsed = ((Date.now() - START_TIME) / 1000).toFixed(2);
  console.log(`[${timestamp}] [${elapsed}s] [${level}] ${message}`);
}

function exec(command, options = {}) {
  log(`Executing: ${command}`);
  try {
    return execSync(command, {
      stdio: 'inherit',
      maxBuffer: 50 * 1024 * 1024,
      ...options
    });
  } catch (error) {
    log(`Command failed: ${command}`, 'ERROR');
    process.exit(1);
  }
}

function checkCache(cacheKey) {
  const cacheFile = `.cache/${cacheKey}`;
  if (fs.existsSync(cacheFile)) {
    const cached = JSON.parse(fs.readFileSync(cacheFile, 'utf8'));
    const lockHash = fs.existsSync('package-lock.json') 
      ? execSync('md5sum package-lock.json', { encoding: 'utf8' }).split(' ')[0]
      : execSync('md5sum yarn.lock', { encoding: 'utf8' }).split(' ')[0];
    
    if (cached.hash === lockHash) {
      log(`Cache hit for ${cacheKey}`);
      return true;
    }
  }
  return false;
}

function saveCache(cacheKey) {
  const lockHash = fs.existsSync('package-lock.json')
    ? execSync('md5sum package-lock.json', { encoding: 'utf8' }).split(' ')[0]
    : execSync('md5sum yarn.lock', { encoding: 'utf8' }).split(' ')[0];
  
  if (!fs.existsSync('.cache')) {
    fs.mkdirSync('.cache', { recursive: true });
  }
  
  fs.writeFileSync(`.cache/${cacheKey}`, JSON.stringify({ hash: lockHash, timestamp: Date.now() }));
}

function installDependencies() {
  log('Installing dependencies...');
  
  if (checkCache('dependencies')) {
    log('Dependencies unchanged, skipping install');
    return;
  }
  
  if (fs.existsSync('yarn.lock')) {
    exec('yarn install --frozen-lockfile --prefer-offline --network-timeout 100000');
  } else if (fs.existsSync('pnpm-lock.yaml')) {
    exec('pnpm install --frozen-lockfile --prefer-offline');
  } else {
    exec(`npm ci --prefer-offline --no-audit --progress=false --maxsockets=${PARALLEL_JOBS}`);
  }
  
  saveCache('dependencies');
  log('Dependencies installed successfully');
}

function runLinting() {
  log('Running linting...');
  
  if (fs.existsSync('node_modules/.bin/eslint')) {
    exec('npm run lint --if-present || npx eslint . --ext .js,.jsx,.ts,.tsx --max-warnings 0 --cache --cache-location .cache/eslint || true');
  }
  
  log('Linting completed');
}

function runTests() {
  log('Running tests...');
  
  const testCommand = fs.existsSync('jest.config.js') || fs.existsSync('jest.config.ts')
    ? `npx jest --maxWorkers=${PARALLEL_JOBS} --coverage --ci --bail`
    : 'npm test';
  
  exec(testCommand);
  log('Tests passed successfully');
}

function buildApplication() {
  log('Building application...');
  
  if (checkCache('build')) {
    log('Build unchanged, skipping');
    return;
  }
  
  if (fs.existsSync('next.config.js')) {
    exec('npm run build || npx next build');
  } else if (fs.existsSync('vite.config.js') || fs.existsSync('vite.config.ts')) {
    exec('npm run build || npx vite build');
  } else if (fs.existsSync('webpack.config.js')) {
    exec('npm run build || npx webpack --mode production');
  } else if (fs.existsSync('tsconfig.json')) {
    exec(`npx tsc --build --force`);
  } else {
    exec('npm run build');
  }
  
  saveCache('build');
  log('Build completed successfully');
}

function optimizeBuild() {
  log('Optimizing build artifacts...');
  
  if (fs.existsSync('dist') || fs.existsSync('build') || fs.existsSync('.next')) {
    const buildDir = fs.existsSync('dist') ? 'dist' : fs.existsSync('build') ? 'build' : '.next';
    
    exec(`find ${buildDir} -name "*.map" -type f -delete || true`, { stdio: 'pipe' });
    exec(`find ${buildDir} -name "*.test.js" -type f -delete || true`, { stdio: 'pipe' });
    
    log('Build artifacts optimized');
  }
}

function deployToProduction() {
  log('Deploying to production...');
  
  const deployMethod = process.env.DEPLOY_METHOD || 'docker';
  const deployTarget = process.env.DEPLOY_TARGET || 'production';
  
  switch (deployMethod) {
    case 'docker':
      deployDocker();
      break;
    case 'ssh':
      deploySSH();
      break;
    case 'aws':
      deployAWS();
      break;
    case 'vercel':
      deployVercel();
      break;
    case 'heroku':
      deployHeroku();
      break;
    default:
      log('No deployment method specified, skipping deployment', 'WARN');
  }
  
  log('Deployment completed successfully');
}

function deployDocker() {
  const imageName = process.env.DOCKER_IMAGE || 'app';
  const registry = process.env.DOCKER_REGISTRY || 'docker.io';
  const tag = process.env.GIT_COMMIT || execSync('git rev-parse --short HEAD', { encoding: 'utf8' }).trim();
  
  log('Building Docker image...');
  exec(`docker build --build-arg BUILDKIT_INLINE_CACHE=1 --cache-from ${registry}/${imageName}:latest -t ${registry}/${imageName}:${tag} -t ${registry}/${imageName}:latest .`);
  
  log('Pushing Docker image...');
  exec(`docker push ${registry}/${imageName}:${tag}`);
  exec(`docker push ${registry}/${imageName}:latest`);
  
  if (process.env.KUBERNETES_DEPLOYMENT) {
    log('Deploying to Kubernetes...');
    exec(`kubectl set image deployment/${process.env.KUBERNETES_DEPLOYMENT} ${process.env.KUBERNETES_CONTAINER}=${registry}/${imageName}:${tag}`);
    exec(`kubectl rollout status deployment/${process.env.KUBERNETES_DEPLOYMENT} --timeout=300s`);
  }
}

function deploySSH() {
  const host = process.env.SSH_HOST;
  const user = process.env.SSH_USER || 'deploy';
  const path = process.env.DEPLOY_PATH || '/var/www/app';
  
  log('Deploying via SSH...');
  exec(`rsync -avz --delete --exclude node_modules --exclude .git -e "ssh -o StrictHostKeyChecking=no" ./ ${user}@${host}:${path}/`);
  exec(`ssh -o StrictHostKeyChecking=no ${user}@${host} "cd ${path} && npm ci --production && pm2 restart all || pm2 start ecosystem.config.js"`);
}

function deployAWS() {
  const bucket = process.env.AWS_S3_BUCKET;
  const distribution = process.env.AWS_CLOUDFRONT_DISTRIBUTION;
  const buildDir = fs.existsSync('dist') ? 'dist' : fs.existsSync('build') ? 'build' : '.next';
  
  log('Deploying to AWS S3...');
  exec(`aws s3 sync ${buildDir} s3://${bucket}/ --delete --cache-control max-age=31536000,public`);
  
  if (distribution) {
    log('Invalidating CloudFront cache...');
    exec(`aws cloudfront create-invalidation --distribution-id ${distribution} --paths "/*"`);
  }
}

function deployVercel() {
  log('Deploying to Vercel...');
  exec('npx vercel --prod --yes --token=$VERCEL_TOKEN');
}

function deployHeroku() {
  const app = process.env.HEROKU_APP;
  log('Deploying to Heroku...');
  exec(`git push https://heroku:$HEROKU_API_KEY@git.heroku.com/${app}.git HEAD:main --force`);
}

function runHealthCheck() {
  const healthUrl = process.env.HEALTH_CHECK_URL;
  
  if (!healthUrl) {
    log('No health check URL specified, skipping', 'WARN');
    return;
  }
  
  log('Running health check...');
  
  for (let i = 0; i < 30; i++) {
    try {
      exec(`curl -f -s -o /dev/null -w "%{http_code}" ${healthUrl}`, { stdio: 'pipe' });
      log('Health check passed');
      return;
    } catch (error) {
      log(`Health check attempt ${i + 1} failed, retrying...`, 'WARN');
      execSync('sleep 2');
    }
  }
  
  log('Health check failed after 30 attempts', 'ERROR');
  process.exit(1);
}

function cleanup() {
  log('Cleaning up...');
  
  exec('rm -rf .cache/eslint || true', { stdio: 'pipe' });
  exec('docker system prune -f || true', { stdio: 'pipe' });
  
  log('Cleanup completed');
}

function main() {
  log('Starting CI/CD pipeline...');
  
  try {
    installDependencies();
    
    if (process.env.SKIP_LINT !== 'true') {
      runLinting();
    }
    
    if (process.env.SKIP_TESTS !== 'true') {
      runTests();
    }
    
    buildApplication();
    optimizeBuild();
    
    if (process.env.SKIP_DEPLOY !== 'true') {
      deployToProduction();
      
      if (process.env.HEALTH_CHECK_URL) {
        runHealthCheck();
      }
    }
    
    cleanup();
    
    const totalTime = ((Date.now() - START_TIME) / 1000).toFixed(2);
    log(`Pipeline completed successfully in ${totalTime}s`, 'SUCCESS');
    
  } catch (error) {
    log(`Pipeline failed: ${error.message}`, 'ERROR');
    process.exit(1);
  }
}

main();